import React, { Component } from "react";
import {
  Button,
  Modal,
  ModalHeader,
  ModalBody,
  ModalFooter,
  FormGroup,
  Label,
  Input
} from "reactstrap";

class CheatsModal extends Component {
  render() {
    const {
      isOpen,
      toggle,
      cheatsList,
      handleToggleCheat,
      handleRemoveCheat,
      handleAddCheat,
      newCheatName,
      newCheatCode,
      setNewCheatName,
      setNewCheatCode
    } = this.props;

    return (
      <Modal
        isOpen={isOpen}
        toggle={toggle}
        className="CheatsModal"
        fade={false}
      >
        <ModalHeader toggle={toggle}>Gerenciador de Trapaças (Cheats)</ModalHeader>
        <ModalBody>
          <h5>Trapaças Disponíveis</h5>
          {cheatsList.length === 0 ? (
            <p>Nenhuma trapaça cadastrada para este jogo.</p>
          ) : (
            <ul style={{ listStyleType: "none", paddingLeft: 0 }}>
              {cheatsList.map((cheat, index) => (
                <li key={index} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "10px", borderBottom: "1px solid #eee", paddingBottom: "5px" }}>
                  <div>
                    <strong>{cheat.name}</strong> <span style={{ fontFamily: "monospace", background: "#f1f1f1", padding: "2px 5px", borderRadius: "3px", marginLeft: "5px" }}>{cheat.code}</span>
                  </div>
                  <div>
                    <Button
                      color={cheat.enabled ? "success" : "secondary"}
                      size="sm"
                      onClick={() => handleToggleCheat(index)}
                      style={{ marginRight: "5px" }}
                    >
                      {cheat.enabled ? "Ativado" : "Desativado"}
                    </Button>
                    {cheat.custom && (
                      <Button
                        color="danger"
                        size="sm"
                        onClick={() => handleRemoveCheat(index)}
                      >
                        Remover
                      </Button>
                    )}
                  </div>
                </li>
              ))}
            </ul>
          )}
          <hr />
          <h5>Adicionar Trapaça Personalizada (Game Genie)</h5>
          <form onSubmit={handleAddCheat}>
            <FormGroup>
              <Label for="cheatName">Nome da Trapaça</Label>
              <Input
                type="text"
                id="cheatName"
                placeholder="Ex: Vidas Infinitas"
                value={newCheatName}
                onChange={e => setNewCheatName(e.target.value)}
              />
            </FormGroup>
            <FormGroup>
              <Label for="cheatCode">Código Game Genie</Label>
              <Input
                type="text"
                id="cheatCode"
                placeholder="Ex: SLAIYG"
                value={newCheatCode}
                onChange={e => setNewCheatCode(e.target.value)}
              />
            </FormGroup>
            <Button color="primary" type="submit">Adicionar Código</Button>
          </form>
        </ModalBody>
        <ModalFooter>
          <Button outline color="primary" onClick={toggle}>
            Fechar
          </Button>
        </ModalFooter>
      </Modal>
    );
  }
}

export default CheatsModal;
