import React, { Component } from "react";
import { Progress } from "reactstrap";
import { Link } from "react-router-dom";

import config from "./config";
import ControlsModal from "./ControlsModal";
import CheatsModal from "./CheatsModal";
import Emulator from "./Emulator";
import RomLibrary from "./RomLibrary";
import { PREDEFINED_CHEATS } from "./CheatManager";
// import NESCntlr from 'nes-cntlr';


import "./RunPage.css";
import VirtualController from "./VirtualController";

function loadBinary(path, callback, handleProgress) {
  var req = new XMLHttpRequest();
  req.open("GET", path);
  req.overrideMimeType("text/plain; charset=x-user-defined");
  req.onload = function () {
    if (this.status === 200) {
      if (req.responseText.match(/^<!doctype html>/i)) {
        // Got HTML back, so it is probably falling back to index.html due to 404
        return callback(new Error("Page not found"));
      }

      callback(null, this.responseText);
    } else if (this.status === 0) {
      // Aborted, so ignore error
    } else {
      callback(new Error(req.statusText));
    }
  };
  req.onerror = function () {
    callback(new Error(req.statusText));
  };
  req.onprogress = handleProgress;
  req.send();
  return req;
}

/*
 * The UI for the emulator. Also responsible for loading ROM from URL or file.
 */
class RunPage extends Component {
  constructor(props) {
    super(props);
    this.state = {
      romName: null,
      romData: null,
      running: false,
      paused: false,
      controlsModalOpen: false,
      loading: true,
      loadedPercent: 3,
      error: null,
      cheatsModalOpen: false,
      cheatsList: [],
      newCheatName: "",
      newCheatCode: ""
    };
  }

  render() {
    return (
      <div className="RunPage">
        {/* <ul className="navbar-nav ml-auto mr-auto">
            <li className="navitem">
             <p><span className="navbar-text mr-3">{this.state.romName}</span></p> 
             <p><span className="navbar-text mr-3">DPad: Setas | Start: Enter | Select: CTRL Direito | Botão A: Z | Botão B: X</span></p>
            </li>
          </ul> */}
        <div className="runpage-container">

          {/* <Button
                outline
                color="primary"
                onClick={this.toggleControlsModal}
                className="mr-3"
              >
                Controles
              </Button>  */}

          {/* <Button
                outline
                color="primary"
                onClick={this.handlePauseResume}
                disabled={!this.state.running}
              >
                {this.state.paused ? "Continue" : "Pause"}
              </Button> */}
          {this.state.error ? (
            this.state.error
          ) : (
            <div
              className="screen-container"
              ref={el => {
                this.screenContainer = el;
              }}
            >
              <div>
                <div>
                  <p style={{ margin: "0" }}>{this.state.romName}</p>
                </div>
                <p style={{ margin: "0" }}>Padrão: DPad: Setas | Start: Enter | Select: CTRL | Botão A: X | Botão B: Z
                </p>
                {this.state.paused ? (
                  <a style={{ "text-decoration": "none" }} onClick={this.handlePauseResume} className="no-underline"> Continuar Emulador ( <i className="fa fa-play-circle "></i> ) </a>
                ) : (
                  <a style={{ "text-decoration": "none" }} onClick={this.handlePauseResume} className="no-underline"> Pausar Emulador ( <i className="fa fa-pause"></i> ) </a>
                )}
                -  <a style={{ "text-decoration": "none" }} onClick={this.handleReset} className="no-underline"> Resetar Emulador ( <i className="fa fa-refresh"></i> ) </a>
                -  <a style={{ "text-decoration": "none" }} onClick={this.toggleControlsModal} className="no-underline"> Configurar Controles ( <i className="fa fa-gamepad"></i> )</a>
                -  <a style={{ "text-decoration": "none" }} onClick={this.toggleCheatsModal} className="no-underline"> Trapaças / Cheats ( <i className="fa fa-magic"></i> )</a>
              </div>
              {this.state.loading ? (
                <Progress
                  value={this.state.loadedPercent}
                  style={{
                    position: "absolute",
                    width: "70%",
                    left: "15%",
                    top: "48%"
                  }}
                />
              ) : this.state.romData ? (
                <Emulator
                  romData={this.state.romData}
                  paused={this.state.paused}
                  activeCheats={this.state.cheatsList}
                  ref={emulator => {
                    this.emulator = emulator;
                  }}
                />
              ) : null}

              {/* TODO: lift keyboard and gamepad state up */}
              {this.state.controlsModalOpen && (
                <ControlsModal
                  isOpen={this.state.controlsModalOpen}
                  toggle={this.toggleControlsModal}
                  keys={this.emulator.keyboardController.keys}
                  setKeys={this.emulator.keyboardController.setKeys}
                  promptButton={this.emulator.gamepadController.promptButton}
                  gamepadConfig={this.emulator.gamepadController.gamepadConfig}
                  setGamepadConfig={
                    this.emulator.gamepadController.setGamepadConfig
                  }
                />
              )}
              {this.state.cheatsModalOpen && (
                <CheatsModal
                  isOpen={this.state.cheatsModalOpen}
                  toggle={this.toggleCheatsModal}
                  cheatsList={this.state.cheatsList}
                  handleToggleCheat={this.handleToggleCheat}
                  handleRemoveCheat={this.handleRemoveCheat}
                  handleAddCheat={this.handleAddCheat}
                  newCheatName={this.state.newCheatName}
                  newCheatCode={this.state.newCheatCode}
                  setNewCheatName={(val) => this.setState({ newCheatName: val })}
                  setNewCheatCode={(val) => this.setState({ newCheatCode: val })}
                />
              )}
              <div style={{ "z-index": "10000" }} id="nes-pad">
                <VirtualController />
              </div>


            </div>
          )}
        </div>
        <nav
          className="navbar"
          ref={el => {
            this.navbar = el;
          }}
        >
        </nav>
      </div>
    );
  }

  componentDidMount() {
    window.addEventListener("resize", this.layout);
    this.layout();
    this.load();
    // let player1 = new NESCntlr({
    //   virtual: 'always',
    //   location: '#controle-nes'
    // });

    // player1.init();

  }

  componentWillUnmount() {
    window.removeEventListener("resize", this.layout);
    if (this.currentRequest) {
      this.currentRequest.abort();
    }
  }

  load = () => {
    if (true) {
      const eggs = ["gradius", "lf", "contra", "dh", "duckh", "sevensix", "tn2", "cv"];
      var egg = eggs[Math.floor(Math.random() * eggs.length)];
      // var egg = "cv";

      const slug = egg;
      const predefined = PREDEFINED_CHEATS[slug] || [];
      const cheatsList = predefined.map(cheat => ({ ...cheat, enabled: false }));
      this.setState({ cheatsList });

      const isLocalROM = /^local-/.test(slug);
      const romHash = slug.split("-")[1];
      const romInfo = isLocalROM
        ? RomLibrary.getRomInfoByHash(romHash)
        : config.ROMS[slug];

      if (!romInfo) {
        this.setState({ error: `ROM inválida: ${slug}` });
        return;
      }

      if (isLocalROM) {
        this.setState({ romName: romInfo.name });
        const localROMData = localStorage.getItem("blob-" + romHash);
        this.handleLoaded(localROMData);
      } else {
        this.setState({ romName: romInfo.description });
        this.currentRequest = loadBinary(
          romInfo.url,
          (err, data) => {
            if (err) {
              this.setState({ error: `Error loading ROM: ${err.message}` });
            } else {
              this.handleLoaded(data);
            }
          },
          this.handleProgress
        );
      }
    } else if (this.props.location.state && this.props.location.state.file) {
      let reader = new FileReader();
      reader.readAsBinaryString(this.props.location.state.file);
      reader.onload = e => {
        this.currentRequest = null;
        this.handleLoaded(reader.result);
      };
    } else {
      this.setState({ error: "No ROM provided" });
    }
  };

  handleProgress = e => {
    if (e.lengthComputable) {
      this.setState({ loadedPercent: (e.loaded / e.total) * 100 });
    }
  };

  handleLoaded = data => {
    this.setState({ running: true, loading: false, romData: data });
  };

  handlePauseResume = () => {
    this.setState({ paused: !this.state.paused });
  };

  handleReset = () => {
    if (this.emulator) {
      this.emulator.reset();
    }
  };

  layout = () => {
    let navbarHeight = parseFloat(window.getComputedStyle(this.navbar).height);

    const isTouch = (('ontouchstart' in window) ||
      (navigator.maxTouchPoints > 0) ||
      (navigator.msMaxTouchPoints > 0));

    let offset = 145;
    if (isTouch) {
      const cntlrEl = document.querySelector('.cntlr');
      if (cntlrEl) {
        offset += cntlrEl.getBoundingClientRect().height + 15;
      } else {
        offset += 165; // Fallback default
      }
    }

    this.screenContainer.style.height = `${window.innerHeight - offset}px`;
    if (this.emulator) {
      this.emulator.fitInParent();
    }
  };

  toggleControlsModal = () => {
    this.setState({ controlsModalOpen: !this.state.controlsModalOpen });
  };

  toggleCheatsModal = () => {
    this.setState({ cheatsModalOpen: !this.state.cheatsModalOpen });
  };

  handleToggleCheat = (index) => {
    const cheatsList = this.state.cheatsList.map((cheat, i) => {
      if (i === index) {
        return { ...cheat, enabled: !cheat.enabled };
      }
      return cheat;
    });
    this.setState({ cheatsList });
  };

  handleAddCheat = (e) => {
    e.preventDefault();
    const name = this.state.newCheatName || "";
    const code = (this.state.newCheatCode || "").trim().toUpperCase();

    if (!name || !code) {
      alert("Por favor, preencha o nome e o código do cheat.");
      return;
    }

    const GG_REGEX = /^[APZLGITYEOXUKSVN]{6,8}$/;
    if (!GG_REGEX.test(code)) {
      alert("Código Game Genie inválido! O código deve ter 6 ou 8 letras e conter apenas os caracteres permitidos: A P Z L G I T Y E O X U K S V N");
      return;
    }

    const newCheat = { name, code, enabled: true, custom: true };
    this.setState({
      cheatsList: [...this.state.cheatsList, newCheat],
      newCheatName: "",
      newCheatCode: ""
    });
  };

  handleRemoveCheat = (index) => {
    const cheatsList = this.state.cheatsList.filter((_, i) => i !== index);
    this.setState({ cheatsList });
  };
}

export default RunPage;
