export function decodeGameGenie(code) {
  const cleanCode = code.toUpperCase().replace(/[^A-Z]/g, "");
  if (cleanCode.length !== 6 && cleanCode.length !== 8) return null;

  const n = [];
  for (let i = 0; i < cleanCode.length; i++) {
    const val = CHAR_MAP[cleanCode[i]];
    if (val === undefined) return null;
    n.push(val);
  }

  // Decode address
  const address = 0x8000 |
    ((n[3] & 7) << 12) |
    ((n[5] & 7) << 8) |
    ((n[4] & 8) << 8) |
    ((n[2] & 7) << 4) |
    ((n[1] & 8) << 4) |
    (n[4] & 7) |
    (n[3] & 8);

  let value = 0;
  let compare = null;

  if (cleanCode.length === 6) {
    value = ((n[1] & 7) << 4) | ((n[0] & 8) << 4) | (n[0] & 7) | (n[5] & 8);
  } else {
    value = ((n[1] & 7) << 4) | ((n[0] & 8) << 4) | (n[0] & 7) | (n[7] & 8);
    compare = ((n[7] & 7) << 4) | ((n[6] & 8) << 4) | (n[6] & 7) | (n[5] & 8);
  }

  return { address, value, compare };
}
