import React, { Component } from 'react';
import data from './../Json/data';
const d = new Date();
let year = d.getFullYear();

const jsonData = data.main;
class Footer extends Component {
  constructor(props) {
    super(props);
    this.state = {
      isSmallTouch: false
    };
  }

  componentDidMount() {
    const checkDevice = () => {
      const isTouch = (('ontouchstart' in window) ||
         (navigator.maxTouchPoints > 0) ||
         (navigator.msMaxTouchPoints > 0));
      const isSmall = window.innerWidth < 992;
      this.setState({ isSmallTouch: isTouch && isSmall });
    };

    checkDevice();
    window.addEventListener('resize', checkDevice);
    this.cleanupResize = () => window.removeEventListener('resize', checkDevice);
  }

  componentWillUnmount() {
    if (this.cleanupResize) {
      this.cleanupResize();
    }
  }

  render() {

    if(jsonData){
      var networks= jsonData.social.map(function(network){
        return <li alt={network.name} title={network.name} key={network.name}><a target="_blank" href={network.url}><i className={network.className}></i></a></li>
      })
    }

    const codeText = this.state.isSmallTouch ? "↑ ↑ ↓ ↓ ← → ← → Tap Tap" : "↑ ↑ ↓ ↓ ← → ← → B A";

    return (
      <footer>

     <div className="row">
        <div className="twelve columns">
           <ul className="social-links">
              {networks}
           </ul>

           <ul className="copyright">
              <li>Made with <span className="love">♥</span> using <b>ReactJS</b></li>
              <li><b>Rodrigo A. Melo</b></li>
              <li><b>Londrina</b>/PR - <b>{year}</b></li>
           </ul>
           <ul className="copyright">
              <li className="konami-hidden">{codeText}</li>
           </ul>

        </div>
        <div id="go-top"><a className="smoothscroll" title="Voltar ao topo" href="#home"><i className="icon-up-open"></i></a></div>
     </div>
  </footer>
    );
  }
}

export default Footer;
